const applicants = [
  { id: 'A001', name: 'Applicant A', company_size: 45, role: 'Project Manager', tool_used: 'Asana', months_using_our_product: 4, weekly_tasks: 38, team_size: 12, willing_to_interview: true, timezone: 'UTC+2', email: 'a@example.com' },
  { id: 'A002', name: 'Applicant B', company_size: 12, role: 'Founder', tool_used: 'Spreadsheet', months_using_our_product: 1, weekly_tasks: 9, team_size: 3, willing_to_interview: true, timezone: 'UTC-5', email: 'b@example.com' },
  { id: 'A003', name: 'Applicant C', company_size: 250, role: 'Head of PMO', tool_used: 'Monday.com', months_using_our_product: 7, weekly_tasks: 190, team_size: 45, willing_to_interview: true, timezone: 'UTC+0', email: 'c@example.com' },
  { id: 'A004', name: 'Applicant D', company_size: 5, role: 'Designer', tool_used: 'Notion', months_using_our_product: 2, weekly_tasks: 6, team_size: 2, willing_to_interview: false, timezone: 'UTC+3', email: 'd@example.com' },
  { id: 'A005', name: 'Applicant E', company_size: 80, role: 'Product Manager', tool_used: 'Jira', months_using_our_product: 5, weekly_tasks: 55, team_size: 20, willing_to_interview: true, timezone: 'UTC-8', email: 'e@example.com' }
];
const criteria = {
  min_company_size: 20,
  max_company_size: 500,
  required_roles: ['Project Manager', 'Product Manager', 'Head of PMO', 'Engineering Manager'],
  min_months_using: 3,
  min_weekly_tasks: 20,
  willing_to_interview: true,
  target_count: 8
};
return [{ json: { applicants, criteria, study_name: 'Mid-Market PM Adoption Study — Q3 2026' } }];

// Score applicants deterministically — no LLM needed
const { applicants, criteria, study_name } = $input.first().json;
const scored = applicants.map(a => {
  const checks = {
    company_size: a.company_size >= criteria.min_company_size && a.company_size <= criteria.max_company_size,
    role: criteria.required_roles.includes(a.role),
    months_using: a.months_using_our_product >= criteria.min_months_using,
    weekly_tasks: a.weekly_tasks >= criteria.min_weekly_tasks,
    willing: a.willing_to_interview === criteria.willing_to_interview
  };
  const passed_count = Object.values(checks).filter(Boolean).length;
  const total = Object.keys(checks).length;
  const qualifies = Object.values(checks).every(Boolean);
  return { ...a, screening: { checks, passed_count, total, qualifies, score_pct: Math.round((passed_count/total)*100) } };
});
const qualified = scored.filter(a => a.screening.qualifies);
const rejected = scored.filter(a => !a.screening.qualifies);
return [{ json: { scored, qualified, rejected, study_name, criteria, meta: { total: applicants.length, qualified_count: qualified.length, rejected_count: rejected.length, checked_at: new Date().toISOString() } } }];

const { qualified, rejected, study_name, meta, criteria } = $input.first().json;
const qualLines = qualified.map(a => `  [QUALIFIED] ${a.id} | ${a.role} | ${a.company_size} employees | ${a.months_using_our_product}mo using | ${a.weekly_tasks} tasks/wk | ${a.timezone}`).join('\n');
const rejLines = rejected.map(a => {
  const fails = Object.entries(a.screening.checks).filter(([k,v])=>!v).map(([k])=>k);
  return `  [REJECTED] ${a.id} | ${a.role} | Failed: ${fails.join(', ')}`;
}).join('\n');
const report = [
  `PARTICIPANT SCREENING RESULTS: ${study_name}`,
  `Screened: ${meta.total} | Qualified: ${meta.qualified_count} | Rejected: ${meta.rejected_count}`,
  `Generated: ${meta.checked_at}`,
  ``,
  `CRITERIA:`,
  `  Company size: ${criteria.min_company_size}–${criteria.max_company_size} employees`,
  `  Roles: ${criteria.required_roles.join(', ')}`,
  `  Min usage: ${criteria.min_months_using} months | Min weekly tasks: ${criteria.min_weekly_tasks}`,
  ``,
  `QUALIFIED APPLICANTS (${meta.qualified_count}):`,
  qualLines || '  (none)',
  ``,
  `REJECTED APPLICANTS (${meta.rejected_count}):`,
  rejLines || '  (none)',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
